B.Lx=new A.p("ln4knl/3r1bg2/p1sp1gspp/2p1ppp2/1p1P5/2PGP1PP1/PPS2PS1P/1KGB3R1/LN5NL b -","Diagram 2-4")
B.afc=new A.c("White will then shift the Rook on the 6th file, so that he can play P6d, Px6d, Sx6d.")
B.akH=new A.c("Remember, you had better not try to keep the vanguard Pawn at the cost of breaking a part of the castle. Especially when playing the Yagura, don't think of having a vanguard Pawn unless your left Silver can go up to support the Pawn.")
