B.ah6=new A.c("The series of moves above leaves White's camp in a complete mess with most of the pieces disconnected with each other, while Black has at least two possibilities to play: S*5c and R6f. Either looks good.")
B.afF=new A.c("Diagram 3 clearly shows Black is dominant at this point.")
B.V2=A.a(s([B.aiu,B.ahE,B.N2,B.ahv,B.a9M,B.ahm,B.a7P,B.LL,B.afU,B.aaa,B.N0,B.ah6,B.afF]),t.A)
