B.Ox=new A.p("lr5nl/5bgk1/p1ns1gspp/2ppp1p2/1p3P1P1/2PPPBP2/PPSG1SN1P/1KG4R1/LN6L w p","Diagram 3")
B.ahF=new A.c("White's R8a was obviously a slack move allowing Black to have the 4e vanguard Pawn. Black can then place his Bishop in an ideal square, 4f, which is effective both in offence and defense.")
