B.SV=A.a(s([B.acn]),t.l)
B.aor=new A.be(27,B.bs,"The 4e Vanguard Pawn is the Tennozan Mountain","4-5 no kurai wa Tennozan",B.SV)
B.O_=new A.p("6snl/6gb1/5pppp/9/7P1/9/6P1P/7R1/7NL b -","Diagram 1-1")
B.ail=new A.c("A series of moves that starts from Diagram 1-1 and ends with Black having a Pawn in hand is known as the Pawn-exchange in the Rook file.")
B.T6=A.a(s(["P2d","Px2d","Rx2d","P*2c","R2h"]),t.s)
B.a9o=new A.P("Moves from Diagram 1-1:",B.T6,B.j)
B.ajt=new A.c('The term "Hisha-saki kokan" (Pawn-exchange in the Rook file) is usually applied only to the static Rook opening.')
B.alo=new A.c("The three advantages are:\n(1) You have a Pawn in hand.\n(2) Your Rook can penetrate the opponent's camp in one move.\n(3) Your other pieces can move up more smoothly.")
B.af5=new A.c("Diagram 1-2 (last move S*4a) is an illustration of (2) above.")
B.Ok=new A.p("5s1nl/6gb1/5ppp1/8p/9/8P/6P2/7R1/7NL w P","Diagram 1-2")
B.amG=new A.c("If White responds with G3a or G4b, you can play R4c+, which will lead to a successful position for you.")
