B.abU=new A.ap(B.a1K)
B.afE=new A.c("By exchanging Pawns in the Rook file, you will have a greater choice in your offensive plans.")
B.aeo=new A.c("Diagram 2-1 shows where Black has already exchanged Pawns, and this partial position is what you should remember as your cue for breaking through White's defense.")
B.KP=new A.p("5k1nl/6gb1/5ppp1/8p/9/8P/6P2/7R1/7NL b P","Diagram 2-1")
B.a18=A.a(s(["P1e","Px1e","P*1c"]),t.s)
B.a83=new A.P("Moves from Diagram 2-1:",B.a18,B.j)
B.Ml=new A.p("5k1nl/6gb1/5pppP/9/8p/9/6P2/7R1/7NL w p","Diagram 2-2")
B.adM=new A.c("Begin with the edge-wing attack: P1e, Px1e, P*1c. This is one of the basics. When beginning the edge attack, it is crucial whether you have a Pawn in hand or not.")
B.SP=A.a(s(["Lx1c","S*1b"]),t.s)
B.aa7=new A.P("Moves from Diagram 2-2:",B.SP,B.r)
B.ame=new A.c("If White neglects responding to your P*1c, you can play Lx1e.")
